    \Delta \tilde{X}_j^i &:= \dt \proj{X^i_j}\attN{j}{X} + \sqrt{\dt} \proj{X^i_j} G_{j+1} (X^i_j).
\end{align*}

We recall from Remark~\ref{rem:adapted_coupling_convention} the definition of the filtration \((\mathcal F_j)_{j=0,\dots,L}\), namely
\begin{equ}
\mathcal F_j:=\sigma\!\left(\mathbf{X}_0,\,(G_r^m,G_r)_{1\le r\le j}\right),
\end{equ}
and that \(\mathbf X_j\) is \(\mathcal F_j\)-measurable. We further recall that, conditionally on $\mathcal F_j$, with $x=X_j^i$, the variables $G_{j+1}^m(x)$ and $G_{j+1}(x)$ are centered and have the same covariance $\K(x,x)\Id$. 

Using the inequality $(a+b)^2 \le 2a^2 + 2b^2$, we decompose the cumulative expected supremum $Z_{\ell+1}$ into two terms:
\begin{align}
    Z_{\ell+1} &:= \E\left[\sup_{0\leq k\leq \ell+1} \frac{1}{N}\sum_{i=1}^N \left|\sum_{j=0}^{k-1} (\Delta X_j^i - \Delta \hat{X}_j^i)\right|^2\right] \nonumber \\
    &\leq 2\underbrace{\E\left[\sup_{0\leq k\leq \ell+1} \frac{1}{N}\sum_{i=1}^N \left|\sum_{j=0}^{k-1} (\Delta \tilde{X}_j^i - \Delta \hat{X}_j^i)\right|^2 \right]}_{\text{(A) }} \nonumber \\
    &\quad + 2\underbrace{\E\left[\sup_{0\leq k\leq \ell+1} \frac{1}{N}\sum_{i=1}^N \left|\sum_{j=0}^{k-1} (\Delta X_j^i - \Delta \tilde{X}_j^i)\right|^2 \right]}_{\text{(B) }}.
\end{align}
We now proceed to bound the terms on the RHS separately. \\[10pt]
\noindent \textbf{Bounding (B):} 
By definition of the filtration \((\mathcal F_j)_{j=0,\dots,L}\), 
we note that, since $G_{j+1}^m(x)$ and $G_{j+1}(x)$ are both centered with the same covariance, for any $x \in \S^{d-1}$ we have:
\begin{equ}
\E[\proj{x}(G_{j+1}^m(x)-G_{j+1}(x))\vert \mathcal F_j]=0.
\end{equ}
Therefore, defining  $W_j^i := \Delta X_j^i - \Delta \tilde{X}_j^i$, we get $\E[W_j^i\mid \mathcal F_j]=0$, so $(W_j^i)_j$ is a martingale difference sequence. By Doob's maximal inequality:
\begin{align*}
    (B) &\leq \frac{4}{N}\sum_{i=1}^N \sum_{j=0}^{\ell} \E\left[|W_j^i|^2\right] \\
    &\leq \mathsf c_N T \left(\frac{1}{m} + \dt\right).
\end{align*}
\textbf{Bounding (A):} We further split $\Delta \tilde{X}_j^i - \Delta \hat{X}_j^i$ into a predictable conditional drift $D_j^i$ and a martingale difference $M_j^i$:
\begin{equation*}
    D_j^i := \E[\Delta \tilde{X}_j^i - \Delta \hat{X}_j^i \mid \mathcal{F}_j] \quad \text{and} \quad M_j^i := \Delta \tilde{X}_j^i - \Delta \hat{X}_j^i - D_j^i.
\end{equation*}
Substituting these into the expectation of $\Delta \tilde{X}_j^i$, we obtain the drift term. Since the true particles $X_j^i$ lie strictly on the sphere $\S^{d-1}$, the cutoff function evaluates to $\rho(X_j^i) = 1$. Thus:
\begin{equation*}
    D_j^i = \dt\left( \rdriftN{j}{X} - \rdriftN{j}{\hat{X}} \right).
\end{equation*}
Using Cauchy-Schwarz and the uniform Lipschitz property of the regularized drift:
\begin{align*}
    \E\left[\sup_{0\leq k\leq \ell+1} \frac{1}{N}\sum_{i=1}^N \left|\sum_{j=0}^{k-1} D_j^i\right|^2\right] &\leq \mathsf c T \dt \sum_{j=0}^{\ell} Z_j.
\end{align*}
Since $M_j^i$ is a martingale difference sequence, Doob's maximal inequality yields:
\begin{align*}
    \E\left[\sup_{0\leq k\leq \ell+1} \frac{1}{N}\sum_{i=1}^N \left|\sum_{j=0}^{k-1} M_j^i\right|^2\right] &\leq \mathsf c \dt \sum_{j=0}^{\ell} Z_j + \mathsf c T \dt.
\end{align*}
\textbf{Conclusion:} Combining the bounds, we obtain a recursive bound on the cumulative error:
\begin{equation*}
    Z_{\ell+1} \leq \mathsf c_N\left( \dt + \frac{1}{m} \right) + \mathsf c \dt \sum_{j=0}^{\ell} Z_j.
\end{equation*}
Applying the discrete Gr\"onwall lemma yields the final bound:
\begin{equation*}
    Z_L \leq \mathsf c_N\left(\frac{1}{L} + \frac{1}{m}\right) e^{\mathsf c_NT}.
\end{equation*}
\end{proof}

