    \begin{equ}
        \mathcal{E}_{\mathrm{mlp}}=X_{\ell+1}^i-Y_{\ell}^i-P_{Y_{\ell}^i}\mathbf{w}
        +\frac12|P_{Y_{\ell}^i}\mathbf{w}|^2Y_{\ell}^i
