        B^2_t \leq 4 K_2 \int_0^t 4 K_3 \dt \, \dd u = 16 T K_2 K_3 \dt.
    \end{equation*}

    \textbf{Conclusion:}
    Substituting the four bounds back into the inequality for $Z(t)$:
    \begin{align*}
        Z(t) &\leq 4 \left( T K_2 \int_0^t Z(u) \, \dd u + 4 T^2 K_2 K_3 \dt + 4 K_2 \int_0^t Z(u) \, \dd u + 16 T K_2 K_3 \dt \right) \\
        &= 16 K_2 K_3 (4T + T^2) \dt + 4 K_2(T + 4) \int_0^t Z(u) \, \dd u.
    \end{align*}
    Since $Z(t)$ is the expectation of a supremum, it is non-decreasing, so $Z(t) \le Z(T)$ for all $t \le T$. Thus, the integral term is bounded by $4 K_2(T+4) T Z(T)$, which implies $Z(T) \le 16 K_2 K_3 (4T + T^2) \dt / (1 - 4 K_2(T+4)T)$, showing the error is linear in $\dt$ without needing Gr\"onwall's inequality.
\end{proof}
